import type { Exam } from '../domain/models/Exam';

export const EXAM_3: Exam = {
  title: "Mock Exam 3",
  subtitle: "Full-Length Simulation C — Insurance, Pharma & Energy",
  sections: [
    // SCENARIO 1: Insurance AI (D3 Planning + D4 Implementation)
    { type: "scenario", scenario: "Pinnacle Insurance Group operates across 12 European countries and has deployed three AI systems: an automated claims triage engine that routes claims to adjusters based on predicted complexity, a fraud detection model that flags suspicious claims for investigation, and a customer lifetime value predictor used for policy pricing. The AIMS project manager, Yuki, is conducting the initial context analysis. During interviews, the head of underwriting reveals that the pricing model uses postal code data that correlates with socioeconomic status. The fraud detection model was trained on historical investigation data that over-represents claims from minority communities. Regulators in three countries have issued guidance requiring explainability for insurance AI decisions. Pinnacle also relies on a third-party actuarial modeling vendor whose models feed into the pricing system.", questions: [
      { question: "Yuki identifies that the pricing model uses postal code data correlating with socioeconomic status. How should this be categorized in the AIMS context analysis?", options: ["As an external issue under Clause 4.1, since socioeconomic correlation is driven by external demographic factors beyond the organization's control", "As an internal issue under Clause 4.1, because the decision to use postal code data as a feature is an organizational design choice that creates proxy discrimination risk", "As an interested party requirement under Clause 4.2, since affected customers have expectations about non-discriminatory pricing"], correct: 1, explanation: "The choice to use postal code data is an internal design decision. While external demographics create the correlation, the risk arises from the organization's own feature selection, making it an internal issue under Clause 4.1." },
      { question: "The fraud detection model over-represents minority communities in its training data. When planning risk treatment under Clause 6.1, what should take priority?", options: ["Retraining the model with balanced data and deploying immediately to production to minimize ongoing harm from the biased model", "Conducting a structured risk assessment that evaluates the bias severity, affected populations, regulatory exposure, and reputational impact before selecting and implementing proportionate treatment measures", "Removing the fraud detection model from production until a completely unbiased replacement can be developed and validated"], correct: 1, explanation: "Clause 6.1 requires a systematic approach to risk treatment. Rushing to retrain without assessment (option A) may introduce new risks, while complete removal (option C) may be disproportionate. A structured assessment ensures proportionate, informed treatment." },
      { question: "Three countries have issued explainability guidance for insurance AI. How should Yuki address the variation in regulatory requirements across jurisdictions?", options: ["Apply the strictest country's requirements uniformly across all 12 countries to simplify compliance and ensure maximum coverage", "Map each jurisdiction's requirements as external issues under Clause 4.1 and interested party requirements under Clause 4.2, then determine which must be addressed through the AIMS scope and controls", "Treat explainability as a single Annex A control objective and implement one standard approach, noting jurisdictional variations as observations in the SoA"], correct: 1, explanation: "Clause 4.1 and 4.2 require identifying jurisdiction-specific requirements. Applying the strictest universally (option A) may be inefficient and still miss jurisdiction-specific nuances. A single approach (option C) may not satisfy varied requirements. Mapping each systematically ensures appropriate coverage." },
      { question: "The third-party actuarial vendor's models feed into Pinnacle's pricing system. During scope definition under Clause 4.3, how should this dependency be addressed?", options: ["Exclude the vendor's models from scope since the vendor is responsible for their own model governance, but include a supply chain risk in the risk register", "Include the vendor relationship as an interface and dependency that affects AIMS outcomes, ensuring the scope accounts for how vendor models influence pricing decisions and what controls are needed over externally provided processes", "Include the vendor's entire operation within Pinnacle's AIMS scope to ensure end-to-end control over the pricing pipeline"], correct: 1, explanation: "Clause 4.3 requires considering interfaces and dependencies with activities performed by other organizations. The vendor's models directly affect Pinnacle's AI outputs, so this dependency must be scoped. However, including the vendor's entire operation (option C) exceeds appropriate scope boundaries." },
      { question: "Yuki proposes an AI objective to 'improve fairness in claims processing.' The steering committee asks whether this satisfies Clause 6.2. What is the most appropriate assessment?", options: ["The objective satisfies Clause 6.2 because it directly addresses an AI-specific concern and aligns with the organization's commitment to responsible AI use", "The objective needs refinement to be measurable and time-bound, such as specifying target fairness metrics, measurement methods, responsible parties, and completion timelines", "The objective is too narrow and should be broadened to 'achieve responsible AI across all systems' to cover the organization's full AI portfolio"], correct: 1, explanation: "Clause 6.2 requires objectives to be consistent with the AI policy, measurable, monitored, communicated, and updated. 'Improve fairness' lacks specificity on measurement, timeline, and accountability. Broadening it further (option C) would make it even less actionable." }
    ]},

    // SCENARIO 2: Pharmaceutical AI (D4 Implementation + D5 Monitoring)
    { type: "scenario", scenario: "BioGenesis Pharmaceuticals has implemented an AIMS covering three AI systems: a drug interaction predictor used by pharmacists, a clinical trial patient matching algorithm, and an adverse event detection system that monitors post-market safety data. During a recent internal review, the AI operations team discovered that the drug interaction predictor had been updated with a new training dataset that included data from a recalled study. The patient matching algorithm's documentation has not been updated since initial deployment 18 months ago despite four model retraining cycles. The adverse event detection system runs on infrastructure shared with the marketing analytics team, and access controls have not been reviewed since the system was first deployed.", questions: [
      { question: "The drug interaction predictor was retrained using data from a recalled study. Which AIMS requirements are most directly violated?", options: ["Clause 7.5 documented information requirements, since the data source should have been recorded and the recalled status would have been identified during document control reviews", "Clause 8.1 operational planning and control, which requires established criteria for AI processes including data quality validation, and the Annex A controls related to data governance and quality management", "Clause 6.1 risk assessment, since the risk of using recalled study data should have been identified during the initial risk assessment process"], correct: 1, explanation: "Clause 8.1 requires operational controls with established criteria. Data quality validation procedures should prevent contaminated data from entering training pipelines. While documentation (option A) and risk assessment (option C) are relevant, the primary failure is in operational control of data ingestion processes." },
      { question: "The patient matching algorithm has undergone four retraining cycles without documentation updates. What is the most significant AIMS concern?", options: ["The organization cannot demonstrate that the current model version matches the validated and approved version, undermining traceability and potentially invalidating the AI impact assessment", "The documentation gap is a minor administrative issue that can be corrected by updating the records retroactively before the next audit cycle", "The retraining cycles should have been prevented by change management procedures until documentation was current"], correct: 0, explanation: "Four undocumented retraining cycles mean the organization cannot trace what model is in production, whether changes were assessed for impact, or whether the current model was properly validated. This undermines traceability and may invalidate the impact assessment under Clause 8.4. Retroactive documentation (option B) cannot reconstruct what was actually assessed at each stage." },
      { question: "The adverse event detection system shares infrastructure with marketing analytics and access controls have not been reviewed. Which Annex A control area is most directly implicated?", options: ["Controls related to AI system documentation, since the shared infrastructure arrangement should be documented in the system architecture records", "Controls related to information security and data protection for AI systems, including access management, segregation of environments, and protection of sensitive health data", "Controls related to third-party and supply chain management, since marketing analytics represents a different organizational function with different data governance requirements"], correct: 1, explanation: "Shared infrastructure between a safety-critical health system and marketing analytics creates direct information security and data protection risks. Access controls for sensitive health data must be reviewed and maintained. While documentation (option A) is relevant, the primary risk is unauthorized access to safety-critical health data." },
      { question: "BioGenesis needs to establish monitoring metrics for the drug interaction predictor per Clause 9.1. Which approach best satisfies the requirement?", options: ["Monitor prediction accuracy against a validated reference dataset on a quarterly basis and report results to the AI governance committee", "Define monitoring metrics covering clinical accuracy, false negative rates for dangerous interactions, data drift indicators, model confidence distributions, and user-reported discrepancies, with defined thresholds triggering escalation procedures", "Monitor system uptime and response time as the primary performance indicators, supplemented by annual accuracy testing against updated pharmacological databases"], correct: 1, explanation: "Clause 9.1 requires determining what to monitor, methods for valid results, when to perform monitoring, and when to analyze results. For a safety-critical drug interaction system, monitoring must cover multiple dimensions including clinical safety metrics, not just accuracy (option A) or infrastructure metrics (option C). Defined thresholds and escalation procedures ensure timely response." },
      { question: "During management review, the head of R&D argues that the four undocumented retraining cycles demonstrate the AI team's agility and should be encouraged. How should the AIMS manager respond?", options: ["Agree that agility is important but propose a lightweight post-hoc documentation process to capture key decisions after each retraining cycle", "Explain that operational agility and AIMS compliance are not mutually exclusive, and propose streamlined but mandatory change assessment and documentation procedures that support rapid iteration while maintaining traceability and risk oversight", "Disagree and insist that all model retraining must go through a formal change control board with minimum two-week review cycles to prevent future documentation gaps"], correct: 1, explanation: "The response must balance operational needs with AIMS requirements. Lightweight post-hoc documentation (option A) still fails to assess changes before deployment. Rigid two-week reviews (option C) may be disproportionate. Streamlined mandatory procedures can support agility while maintaining required traceability and risk oversight." }
    ]},

    // SCENARIO 3: Energy/Utilities AI (D3 Planning + D1 Fundamentals)
    { type: "scenario", scenario: "VoltGrid Energy operates a smart grid network using AI for demand forecasting, predictive maintenance of power infrastructure, and dynamic energy pricing for industrial customers. The organization is initiating AIMS implementation. During context analysis, the AIMS team identifies that the demand forecasting model uses weather data from a commercial provider, historical consumption data from smart meters, and economic indicators. The predictive maintenance system processes sensor data from 50,000 endpoints across the grid. The CEO questions whether ISO/IEC 42001 is necessary given that they already comply with energy sector regulations. The AI team lead argues that the dynamic pricing system is 'just an optimization algorithm' and does not constitute an AI system under ISO/IEC 22989.", questions: [
      { question: "The AI team lead argues the dynamic pricing system is an optimization algorithm, not an AI system. How should this be resolved under the AIMS?", options: ["Accept the team lead's technical assessment since they have the deepest understanding of the system's architecture and classification should be determined by the development team", "Evaluate the system against ISO/IEC 22989 definitions: if it uses machine learning, adaptive algorithms, or makes autonomous decisions based on learned patterns, it qualifies as an AI system regardless of how the team describes it", "Classify it as an AI system to be safe, since any system that uses data to make decisions should be included in the AIMS scope to demonstrate comprehensive coverage"], correct: 1, explanation: "Classification must be based on objective criteria from ISO/IEC 22989, not team preferences (option A) or overly inclusive approaches (option C). If the system exhibits AI characteristics such as learning from data or adapting its behavior, it meets the definition regardless of organizational labels." },
      { question: "The CEO questions the need for ISO/IEC 42001 given existing energy sector regulatory compliance. What is the most accurate response?", options: ["Energy sector regulations address operational safety and reliability but typically do not cover AI-specific risks such as model drift, training data bias, algorithmic transparency, and responsible AI lifecycle management that ISO/IEC 42001 addresses", "ISO/IEC 42001 certification is required for energy companies using AI under the EU AI Act's critical infrastructure provisions and should be implemented to avoid regulatory penalties", "The CEO is correct that existing regulations are sufficient since energy sector compliance frameworks are more mature and rigorous than ISO/IEC 42001 requirements"], correct: 0, explanation: "Energy regulations focus on operational safety and reliability but generally lack AI-specific governance requirements. ISO/IEC 42001 addresses distinct AI risks. However, ISO/IEC 42001 certification is not legally mandated by the EU AI Act (option B), and energy regulations, while rigorous for their domain, do not cover AI-specific concerns (option C)." },
      { question: "The demand forecasting model depends on weather data from a commercial provider. When defining the AIMS scope under Clause 4.3, how should this external data dependency be treated?", options: ["Exclude the weather data provider from scope since they are a data supplier, not an AI system provider, and their data is publicly available commercial information", "Include the weather data dependency as an interface with an external organization that affects AIMS outcomes, and establish controls over data quality, continuity, and the impact of data provider changes on model performance", "Include the weather data provider within the AIMS scope boundary and require them to maintain their own AIMS certification as a condition of the supply contract"], correct: 1, explanation: "Clause 4.3 requires considering interfaces and dependencies. External data quality directly affects forecasting accuracy. Excluding it entirely (option A) ignores a critical dependency. Requiring provider AIMS certification (option C) exceeds reasonable scope boundaries. The correct approach is to control the interface." },
      { question: "The predictive maintenance system processes sensor data from 50,000 endpoints. Under the AIMS risk assessment, which risk dimension is most unique to this system compared to traditional predictive maintenance?", options: ["The volume of data creates storage and processing infrastructure risks that must be assessed for capacity planning and disaster recovery purposes", "The AI-specific risks include the model learning spurious correlations from noisy sensor data, concept drift as equipment ages, and the consequences of false negatives missing critical failures in safety-relevant infrastructure", "The cybersecurity risks of 50,000 network-connected sensors create an attack surface that must be assessed under information security management"], correct: 1, explanation: "While infrastructure (option A) and cybersecurity (option C) are valid concerns, they are not AI-specific. The AIMS risk assessment must focus on AI-unique risks: the model learning incorrect patterns, drifting as conditions change, and the safety consequences of AI prediction failures in critical infrastructure." },
      { question: "VoltGrid plans to set AI objectives for the demand forecasting system. Which objective best demonstrates alignment with both Clause 6.2 requirements and responsible AI principles?", options: ["Achieve 98% forecasting accuracy within 12 months by expanding the training dataset to include 5 additional years of historical consumption data", "Reduce demand forecast error by 15% within 9 months while maintaining demographic fairness in pricing outcomes, with monthly accuracy monitoring and quarterly bias assessments reported to the energy equity committee", "Implement a state-of-the-art transformer-based forecasting architecture within 6 months to replace the current statistical model and improve prediction performance across all grid regions"], correct: 1, explanation: "Clause 6.2 requires objectives that are measurable, monitored, and consistent with the AI policy. Option B combines performance improvement with fairness considerations and specifies monitoring frequency and reporting. Option A is measurable but addresses only accuracy. Option C specifies an implementation approach rather than a measurable outcome." }
    ]},

    // SCENARIO 4: Logistics AI (D4 Implementation + D6 Audit)
    { type: "scenario", scenario: "TransGlobal Logistics uses AI for warehouse automation, shipment route optimization, and customs documentation classification. The organization achieved ISO/IEC 42001 certification eight months ago. During the first surveillance audit, the audit team discovers that the customs classification AI was deployed three months after certification without updating the risk assessment or SoA. The warehouse automation system has experienced two incidents where robotic arms deviated from predicted paths, which were resolved operationally but not processed through the AIMS corrective action procedure. Additionally, the route optimization AI now incorporates real-time traffic data from a new provider that was not part of the original AIMS scope assessment. The internal audit program shows that only 60% of planned audits were completed in the current cycle.", questions: [
      { question: "The customs classification AI was deployed without updating the risk assessment or SoA. What audit finding should the surveillance auditor raise?", options: ["Minor nonconformity against Clause 6.1 for not updating the risk assessment, since the existing risk assessment methodology is sound and only needs extension to cover the new system", "Major nonconformity, as deploying a new AI system without risk assessment and SoA update represents a systemic failure in change management and risk governance that affects the AIMS capability to achieve its intended results", "Observation noting that the organization should consider updating its change management procedures to include triggers for new AI system deployments"], correct: 1, explanation: "Deploying an entirely new AI system without risk assessment or SoA update is not a minor gap in an otherwise functioning process. It represents a fundamental failure in the change management and risk governance processes, raising significant doubt about the AIMS capability to control AI-related risks, warranting a major nonconformity." },
      { question: "The robotic arm incidents were resolved operationally but not processed through AIMS corrective action. How should the auditor assess this?", options: ["No finding is warranted since the incidents were resolved and no injuries occurred, demonstrating effective operational response", "Nonconformity against Clause 10.1, as the organization failed to evaluate the need for corrective action to determine root causes and prevent recurrence, even though immediate operational response was adequate", "Observation recommending that the organization consider integrating operational incident response with the AIMS corrective action process for future reference"], correct: 1, explanation: "Clause 10.1 requires reacting to nonconformities and evaluating the need for action to eliminate causes. Operational resolution addresses symptoms but not root causes. Two similar incidents suggest a pattern that corrective action should investigate. This is a nonconformity, not merely an observation." },
      { question: "The route optimization AI now uses a new traffic data provider not included in the original scope assessment. What is the auditor's primary concern?", options: ["The new data provider introduces a supply chain dependency that may affect data quality, availability, and the accuracy of route optimization outputs, and this change was not assessed for its impact on the AIMS", "The new data provider must hold ISO/IEC 42001 certification or equivalent to be included within TransGlobal's AIMS scope boundary", "The change is operationally minor since traffic data is commodity information and the fundamental route optimization model has not changed"], correct: 0, explanation: "Changes to data sources that feed AI systems can affect model performance, data quality, and create new dependencies. Clause 4.3 requires considering interfaces, and changes to these interfaces should trigger reassessment. The provider doesn't need their own certification (option B), and traffic data quality is not trivial for logistics AI (option C)." },
      { question: "Only 60% of planned internal audits were completed. What does this indicate to the surveillance auditor?", options: ["This is an observation, as internal audit completion rates are operational matters and do not directly affect AIMS conformity as long as the audits that were conducted were thorough", "This raises concern about the organization's commitment to Clause 9.2, as the audit program must cover all AIMS processes at planned intervals, and significant shortfalls may indicate inadequate resource allocation or management support", "This is acceptable if the completed 60% covered the highest-risk areas and the remaining audits are rescheduled within the current certification cycle"], correct: 1, explanation: "Clause 9.2 requires audits at planned intervals covering all AIMS processes. A 40% shortfall is significant and may indicate systemic issues with resource allocation or management commitment. While risk-based prioritization is valid (option C), a substantial failure to execute the audit program undermines the AIMS monitoring framework." },
      { question: "The surveillance auditor identifies one major and one minor nonconformity. TransGlobal asks if they can address both during the next surveillance audit rather than immediately. What is the correct response?", options: ["The request is reasonable for the minor nonconformity but not for the major one, which must be addressed and verified before the certification body decides whether to maintain, suspend, or withdraw certification", "Both nonconformities can be deferred to the next surveillance audit as long as TransGlobal submits a corrective action plan within 30 days of the current audit", "The certification body should immediately suspend certification due to the major nonconformity and only reinstate it after both issues are fully resolved and independently verified"], correct: 0, explanation: "Under ISO/IEC 17021-1, major nonconformities require timely resolution and verification. They cannot simply be deferred to the next surveillance. The certification body must evaluate the severity and determine appropriate action. Immediate suspension (option C) may be disproportionate if the major nonconformity can be resolved within an agreed timeframe." }
    ]},

    // SCENARIO 5: Legal Tech AI (D1 Fundamentals + D3 Planning)
    { type: "scenario", scenario: "LexAI Solutions develops AI-powered legal technology products: a contract review system that identifies risks and non-standard clauses, a case outcome predictor used by litigation attorneys, and a regulatory compliance scanner that monitors regulatory changes across jurisdictions. The company is pursuing ISO/IEC 42001 certification. During the planning phase, the AIMS team debates how to classify these systems under the EU AI Act. The case outcome predictor has raised concerns from the judiciary about potential influence on legal proceedings. The contract review system processes client confidential information from major law firms. The compliance team notes that the NIST AI RMF and ISO/IEC 23894 both provide relevant risk management guidance but are unsure how to integrate these with the AIMS.", questions: [
      { question: "The AIMS team debates EU AI Act classification for the case outcome predictor used by litigation attorneys. What is the most likely classification?", options: ["High-risk, as AI systems used in the administration of justice and democratic processes are explicitly identified as high-risk under the EU AI Act", "Limited risk with transparency obligations, since the system provides predictions to assist attorneys rather than making binding legal decisions", "Unacceptable risk, because predicting case outcomes could undermine judicial independence and the right to a fair trial"], correct: 0, explanation: "The EU AI Act explicitly classifies AI systems intended to assist judicial authorities in interpreting facts and law and applying the law as high-risk. While the system assists rather than decides (option B's reasoning), assistance in legal proceedings falls within the high-risk category. It is not prohibited (option C) since it assists rather than replaces judicial decision-making." },
      { question: "The compliance team wants to integrate NIST AI RMF and ISO/IEC 23894 guidance with the AIMS. What is the most appropriate integration approach?", options: ["Use ISO/IEC 42001 as the certifiable management system framework, then map relevant NIST AI RMF functions and ISO/IEC 23894 guidance to specific AIMS clauses and Annex A controls to enrich the risk management approach", "Implement NIST AI RMF as the primary framework since it is more comprehensive, and use ISO/IEC 42001 only for the certification component", "Choose either NIST AI RMF or ISO/IEC 23894 as the risk management methodology and exclude the other to avoid conflicting guidance"], correct: 0, explanation: "ISO/IEC 42001 is the certifiable standard and provides the management system structure. NIST AI RMF and ISO/IEC 23894 are complementary guidance that can inform and enrich the AIMS risk management processes. They are not competing frameworks (option C) and should not displace the certifiable standard (option B)." },
      { question: "The contract review system processes confidential client information from law firms. When establishing the AIMS scope, which interested party requirement is most critical to address?", options: ["The law firms' requirements for data confidentiality, legal professional privilege protection, and assurance that their clients' information is handled in accordance with applicable data protection laws and professional ethics obligations", "The end users' (attorneys') requirements for system accuracy and reliability in identifying contractual risks", "The certification body's requirements for documented information demonstrating how confidential data is protected within the AIMS"], correct: 0, explanation: "While accuracy (option B) and documentation (option C) are important, the law firms entrusting confidential client data have the most critical interested party requirements. Legal professional privilege creates heightened obligations beyond standard data protection, making this the most critical requirement to address in the AIMS." },
      { question: "The judiciary has raised concerns about the case outcome predictor's potential influence on legal proceedings. Under Clause 4.1, how should this be categorized?", options: ["As an internal issue, because the design of the system and how its predictions might influence proceedings is within LexAI's control", "As an external issue, because the judiciary's concerns reflect the broader societal and regulatory environment in which the system operates, and could result in regulatory action or restrictions", "As an interested party requirement under Clause 4.2, since the judiciary is a stakeholder whose specific requirements must be identified and addressed"], correct: 1, explanation: "The judiciary's concerns about AI influence on proceedings represent external environmental factors that could affect LexAI's ability to achieve AIMS outcomes, including potential regulatory restrictions. While the judiciary could also be considered an interested party (option C), the broader societal concern about AI in justice is best categorized as an external issue. The internal design choice (option A) is a separate consideration." },
      { question: "LexAI's risk assessment identifies that the regulatory compliance scanner could miss a critical regulatory change, leading to client non-compliance. The risk owner proposes accepting this risk because the scanner's accuracy rate is 99.2%. What should the AIMS require before this decision is finalized?", options: ["Verification that the 99.2% accuracy rate has been validated against an independent benchmark and confirmation that this performance level meets the monitoring criteria established under Clause 9.1", "Documented justification of the risk acceptance that considers the severity of potential consequences from the 0.8% miss rate, the nature of regulations that might be missed, interested party expectations, and approval from the appropriate management level", "A cost-benefit analysis comparing the expense of improving accuracy above 99.2% against the estimated financial impact of missed regulatory changes on client relationships"], correct: 1, explanation: "Risk acceptance requires documented justification considering consequences, not just probability. A 0.8% miss rate for critical regulatory changes could have severe consequences. The decision must be justified, documented, and approved by appropriate management. Technical validation (option A) is important but insufficient for risk acceptance. Cost-benefit analysis (option C) is one input but not the complete requirement." }
    ]},

    // SCENARIO 6: Insurance Claims Processing (D5 Monitoring + D6 Improvement)
    { type: "scenario", scenario: "Meridian Insurance has been operating its AIMS for 14 months and is preparing for the first surveillance audit. Their AI-powered claims processing system has shown a gradual decline in accuracy from 94% to 87% over the past six months. The internal audit team conducted two audits during this period and reported zero nonconformities in both. Management review meetings have been held quarterly, but the minutes show that the same three improvement opportunities have been discussed at every meeting without any being implemented. A customer complaint was received about an unfairly denied health insurance claim, and the investigation revealed the AI correctly followed its programmed decision logic. The AIMS manager recently resigned, and the role has been vacant for six weeks.", questions: [
      { question: "The claims processing AI accuracy declined from 94% to 87% over six months. Internal audits found zero nonconformities. What does this combination suggest?", options: ["The internal audits were appropriately focused on management system conformity rather than AI performance metrics, which are monitored separately under Clause 9.1", "The internal audit program may lack sufficient scope, depth, or AI technical competence to identify performance-related nonconformities, since a 7% accuracy decline should trigger investigation under monitoring requirements", "The accuracy decline is within normal operational variance and does not constitute a nonconformity unless it falls below a predefined threshold established in the monitoring criteria"], correct: 1, explanation: "A significant accuracy decline over six months, combined with zero audit findings, strongly suggests the internal audits are not examining the right areas or lack technical depth. If monitoring criteria exist (option C), the decline should have been flagged. If they don't exist, that itself is a nonconformity. Zero findings during a period of obvious performance degradation indicates audit weakness." },
      { question: "The same three improvement opportunities have been discussed at four consecutive management reviews without implementation. What AIMS requirement is at risk?", options: ["Clause 9.3 management review requirements are satisfied as long as improvement opportunities are discussed, since implementation is an operational matter outside the scope of management review", "Clause 10.2 continual improvement, because repeatedly identifying but failing to act on improvement opportunities demonstrates that the organization is not effectively pursuing continual improvement of the AIMS", "Clause 5.1 leadership commitment, because top management's failure to drive implementation of discussed improvements indicates inadequate leadership, which is the root cause rather than an improvement failure"], correct: 1, explanation: "While leadership commitment (option C) may be a contributing factor, the most directly applicable requirement is Clause 10.2 continual improvement. The standard requires the organization to continually improve the AIMS, and four cycles of discussion without action demonstrates a failure to act on improvement, not merely a leadership issue. Management review discussion alone (option A) does not satisfy the continual improvement obligation." },
      { question: "The customer complaint investigation found the AI correctly followed its decision logic. The claims team considers this sufficient to close the complaint. Is this appropriate?", options: ["Yes, if the AI operated as designed and within its validated parameters, the complaint is resolved and the investigation demonstrates the system is functioning correctly", "No, the investigation should also examine whether the decision logic itself produces fair and appropriate outcomes, since 'functioning as designed' does not mean 'functioning acceptably' from an AIMS perspective", "Yes, but the complaint should be documented as a risk indicator and monitored for patterns of similar complaints that might warrant future investigation"], correct: 1, explanation: "An AI system correctly executing flawed or unfair logic is still an AIMS concern. The investigation must examine whether the design meets AIMS objectives including fairness requirements. Simply confirming correct execution of potentially problematic logic does not address whether the outcome was appropriate. Documentation as a risk indicator (option C) acknowledges the issue but doesn't adequately investigate it." },
      { question: "The AIMS manager role has been vacant for six weeks. What is the most significant AIMS concern?", options: ["Clause 5.3 requires that roles, responsibilities, and authorities be assigned, and a six-week vacancy in a key role creates a gap in accountability for ensuring the AIMS conforms to requirements and reporting to top management", "The vacancy is operationally significant but not an AIMS conformity issue, since the AIMS should function through documented processes and distributed responsibilities rather than depending on a single individual", "Clause 7.1 resource requirements are not met, as the organization has failed to determine and provide the people resources needed for the AIMS"], correct: 0, explanation: "While the AIMS should not depend entirely on one person (option B), Clause 5.3 specifically requires assigned responsibilities for ensuring AIMS conformity and reporting to top management. A six-week vacancy in this role creates a demonstrable gap in these assigned responsibilities. Resource provision (option C) is also relevant but the primary concern is the gap in assigned authority and accountability." },
      { question: "The surveillance auditor identifies the accuracy decline, stalled improvements, and AIMS manager vacancy. What collective assessment is most appropriate?", options: ["These are three separate minor nonconformities that should be individually documented, with corrective actions required for each within the standard timeframe", "The combination of findings suggests a systemic issue with AIMS effectiveness and continual improvement, potentially warranting a major nonconformity for the overall failure to maintain and improve the management system", "Each finding should be assessed independently: the accuracy decline is a monitoring issue, the stalled improvements are an improvement issue, and the vacancy is a resource issue, with severity determined individually"], correct: 1, explanation: "While each finding could be assessed individually (option C), auditors should consider whether findings collectively indicate a systemic issue. Declining AI performance, stalled improvements, and vacant key role together suggest the AIMS is not effectively maintaining and improving itself, which affects the system's capability to achieve intended results, potentially constituting a major nonconformity." }
    ]},

    // SCENARIO 7: Pharmaceutical Clinical Trials (D2 AIMS Structure + D4 Implementation)
    { type: "scenario", scenario: "NovaPharma is implementing an AIMS for its AI-assisted clinical trial management platform. The platform includes patient eligibility screening, adverse event signal detection, and protocol deviation identification. The implementation team is debating the relationship between ISO/IEC 42001 and their existing ISO 9001 quality management system. The quality manager argues that since both standards follow the Harmonized Structure, they can simply extend their existing QMS documentation to cover AI requirements. A regulatory affairs specialist notes that the clinical trial AI systems are subject to multiple regulatory frameworks including GxP, FDA guidance on AI/ML in medical devices, and the EU AI Act. The CTO has proposed implementing all Annex A and Annex C controls to demonstrate maximum rigor to regulators.", questions: [
      { question: "The quality manager proposes extending existing ISO 9001 QMS documentation to cover ISO/IEC 42001 AI requirements. What is the most accurate assessment?", options: ["The approach is valid because both standards share the Harmonized Structure, so all common clauses can use existing documentation and only AI-specific requirements need additional documentation", "While the Harmonized Structure enables integration through shared clause structure, ISO/IEC 42001 introduces AI-specific requirements in Clauses 6.1.4, 8.4, and Annex A that go beyond typical QMS processes and require purpose-built procedures for AI risk assessment, impact assessment, and AI system lifecycle management", "The approach is fundamentally flawed because ISO/IEC 42001 and ISO 9001 serve different purposes and their documentation cannot be meaningfully integrated"], correct: 1, explanation: "The Harmonized Structure does enable integration (option A is partially correct), and the standards can be integrated (option C is wrong). However, simply extending QMS documentation underestimates the AI-specific requirements that need purpose-built procedures. The correct answer acknowledges both the integration opportunity and the AI-specific additions needed." },
      { question: "The CTO proposes implementing all Annex A and Annex C controls to demonstrate maximum rigor. What is wrong with this approach?", options: ["Control selection must be based on risk assessment results per Clause 6.1; implementing all controls without risk-based justification may waste resources, create unnecessary bureaucracy, and paradoxically demonstrate poor risk management judgment to regulators", "The approach is sound for a heavily regulated pharmaceutical company where demonstrating comprehensive control coverage provides stronger evidence of due diligence to multiple regulatory bodies", "Only Annex A controls are relevant to certification; Annex C controls are informational guidance that cannot be included in the SoA or audited for conformity"], correct: 0, explanation: "Control selection must be risk-based. Implementing everything without justification actually undermines credibility because it suggests the organization cannot distinguish critical from non-critical controls. For regulators, risk-based selection with clear justification demonstrates stronger governance than blanket implementation. Annex C controls can supplement Annex A (option C is incorrect about their role)." },
      { question: "The regulatory affairs specialist identifies overlapping requirements from GxP, FDA AI/ML guidance, and the EU AI Act. How should these be integrated into the AIMS?", options: ["Create separate compliance programs for each regulatory framework to ensure that the distinct requirements of each are fully addressed without conflation", "Map each regulatory framework's requirements to AIMS clauses and Annex A controls, identifying overlaps and gaps, then address all applicable requirements through the unified AIMS framework while maintaining traceability to each source regulation", "Prioritize EU AI Act compliance since it is the most recent regulation and will likely supersede older frameworks over time"], correct: 1, explanation: "The AIMS should serve as an integrating framework. Creating separate programs (option A) creates silos and duplication. Prioritizing one regulation (option C) risks non-compliance with others. Mapping all requirements to the AIMS with traceability ensures comprehensive coverage and efficient governance." },
      { question: "NovaPharma's Harmonized Structure integration means shared management review processes across ISO 9001 and ISO/IEC 42001. What must the integrated management review ensure?", options: ["That AI-specific inputs required by ISO/IEC 42001 Clause 9.3 are explicitly included, such as the status of AI risk treatment, AI system performance metrics, results of AI impact assessments, and changes in the AI regulatory landscape", "That the management review follows ISO 9001 requirements since it is the more established standard, with AI topics added as supplementary agenda items when relevant issues arise", "That separate management reviews are conducted for each standard to ensure that AI-specific topics receive dedicated attention and are not diluted by broader quality management discussions"], correct: 0, explanation: "An integrated management review is valid under the Harmonized Structure but must ensure all standard-specific inputs are covered. ISO/IEC 42001 requires AI-specific review inputs that go beyond ISO 9001's scope. Treating AI as supplementary (option B) risks missing required inputs. Separate reviews (option C) unnecessarily duplicate the process." },
      { question: "The patient eligibility screening AI processes sensitive health data and directly affects clinical trial enrollment. Which combination of AIMS controls is most critical for this system?", options: ["Data governance controls, AI impact assessment procedures under Clause 8.4, human oversight mechanisms, and transparency controls to ensure that screening criteria and their AI-derived basis can be explained to regulatory authorities and ethics committees", "Information security controls, access management procedures, and encryption requirements to protect patient health data throughout the screening process", "Model validation controls, performance monitoring, and documented information requirements to ensure the screening model meets its accuracy specifications"], correct: 0, explanation: "While security (option B) and validation (option C) are necessary, the critical combination for patient eligibility screening includes data governance, impact assessment, human oversight, and transparency. These address the unique risks of an AI system making decisions that affect human participants in clinical trials, where regulatory authorities and ethics committees require explainability." }
    ]},

    // SCENARIO 8: Energy Trading AI (D3 Planning + D5 Monitoring)
    { type: "scenario", scenario: "PowerTrade Energy uses AI for real-time energy market trading, price forecasting, and portfolio risk management. The AI trading system executes thousands of transactions daily with minimal human oversight. During AIMS planning, the risk assessment team debates how to classify AI risks. The head of trading argues that market risk and AI risk are the same thing since the AI system creates the market exposure. The compliance officer notes that the organization is subject to energy market manipulation regulations and questions whether the AI could inadvertently trigger market manipulation patterns. The CFO requests that AI risk appetite be set at the same level as the organization's existing financial risk appetite. An external data breach at a market data provider has temporarily degraded the quality of pricing data feeding the AI system.", questions: [
      { question: "The head of trading argues that market risk and AI risk are the same because the AI creates market exposure. Why is this conflation problematic for the AIMS?", options: ["AI risk and market risk are indeed the same for an AI trading system, and the existing market risk framework should be used without modification to satisfy ISO/IEC 42001 requirements", "AI risk encompasses dimensions beyond market risk, including model reliability, training data quality, algorithmic bias, transparency of decision-making, and the risk that the AI system itself behaves unpredictably, all of which require separate assessment under the AIMS", "The distinction between AI risk and market risk is primarily semantic; what matters is that all risks are documented in a single risk register regardless of categorization"], correct: 1, explanation: "While the AI system creates market exposure, AI-specific risks go beyond financial market risk. The AI could malfunction, learn spurious patterns, degrade over time, or behave unpredictably in ways that pure market risk analysis does not capture. These AI-specific dimensions require separate identification and assessment under the AIMS." },
      { question: "The compliance officer questions whether the AI could inadvertently trigger market manipulation patterns. How should this be addressed in the AIMS risk assessment?", options: ["This is a regulatory compliance concern that belongs in the legal compliance program rather than the AIMS risk assessment, since the AI is not intentionally manipulating markets", "This must be included in the AIMS risk assessment as an AI-specific risk where autonomous system behavior could produce unintended consequences that violate regulatory requirements, regardless of intent", "This risk should be accepted since the AI is optimizing for legitimate trading objectives and any resemblance to manipulation is coincidental and defensible"], correct: 1, explanation: "Unintended consequences of AI behavior are core AIMS risks. The AI system's autonomous trading patterns could create patterns that regulators interpret as manipulation, regardless of intent. This is precisely the type of AI-specific risk that ISO/IEC 42001 requires organizations to assess, as it involves autonomous system behavior producing regulatory consequences." },
      { question: "The CFO requests that AI risk appetite equal the existing financial risk appetite. What is the most appropriate response?", options: ["Financial risk appetite metrics are inappropriate for AI risk because AI risks include non-financial dimensions such as regulatory compliance, reputational harm, and system reliability that cannot be expressed in financial terms alone", "The CFO's request is reasonable since all risks ultimately translate to financial impact, and using established financial risk thresholds provides consistency across the organization's risk management framework", "AI risk appetite should be set independently by the AI governance committee without reference to the organization's overall risk appetite to ensure AI-specific considerations are not diluted"], correct: 0, explanation: "AI risk appetite must account for dimensions beyond financial impact, including regulatory compliance, transparency, reliability, and reputational considerations. While financial impact is important, reducing all AI risks to financial terms misses critical dimensions. However, AI risk appetite should be consistent with (not independent of, per option C) the organization's overall risk framework." },
      { question: "The external data breach at the market data provider has degraded pricing data quality. What AIMS processes should be triggered?", options: ["The incident management process should log the event, but since the breach occurred at an external provider, no AIMS processes need to be triggered until the provider confirms the data quality issue is resolved", "The operational monitoring process should detect the data quality degradation, trigger assessment of the impact on AI system outputs, evaluate whether the AI trading system should continue operating with degraded data, and communicate with relevant interested parties", "The risk assessment should be updated to permanently increase the risk rating for the market data provider, and the organization should begin procurement of an alternative data source"], correct: 1, explanation: "This is an active operational situation requiring immediate response through monitoring and operational controls. Waiting for provider confirmation (option A) could allow the AI to make trading decisions on degraded data. While updating risk assessment may be appropriate later, the immediate need is operational response: detect, assess impact, decide on continued operation, and communicate (option B)." },
      { question: "The AI trading system executes thousands of daily transactions with minimal human oversight. When establishing monitoring criteria under Clause 9.1, what is the most critical consideration?", options: ["The monitoring criteria should focus on trading performance metrics such as profit/loss, trade volume, and portfolio exposure, since these are the primary indicators of whether the AI system is achieving its business objectives", "The monitoring must include AI-specific behavioral indicators such as unusual pattern changes, decision distribution shifts, out-of-distribution input detection, and automated circuit breakers that can halt trading when the AI's behavior deviates from expected parameters", "The monitoring criteria should be identical to those used for human traders, since the AI system is performing the same function and should be held to the same standards"], correct: 1, explanation: "For an autonomous AI trading system, monitoring must go beyond business metrics (option A) to include AI-specific behavioral indicators that can detect when the system is operating outside expected parameters. Human trader metrics (option C) don't capture AI-specific risks like model drift or adversarial inputs. Automated circuit breakers are essential for high-frequency autonomous systems." }
    ]},

    // SCENARIO 9: Legal Document AI (D4 Implementation + D6 Audit)
    { type: "scenario", scenario: "JurisBot provides AI-powered document assembly and legal research tools to mid-size law firms. Their AIMS has been certified for two years. During the recertification audit, the audit team examines the organization's response to a significant incident that occurred eight months ago: the document assembly AI generated a contract clause that contained an incorrect limitation of liability provision, which was used by a client firm in an executed contract. The error was discovered by the client firm's opposing counsel during litigation. JurisBot's investigation attributed the error to a training data update that included a superseded legal template. The organization's corrective action consisted of reverting the training data and retraining the model. The recertification audit also reveals that JurisBot has not conducted an AI impact assessment for a new generative AI feature that drafts legal memoranda.", questions: [
      { question: "The document assembly AI generated an incorrect contract clause due to superseded legal template data in the training set. The corrective action was to revert and retrain. Is this corrective action sufficient?", options: ["Yes, reverting the training data and retraining the model directly addresses the root cause by removing the contaminated data, which is a complete and proportionate corrective action", "No, the corrective action addresses the immediate symptom but does not examine why superseded templates entered the training pipeline, what validation processes failed, whether similar data quality issues exist in other datasets, or whether the affected outputs require client notification", "No, the corrective action is insufficient because the organization should have implemented a completely new data validation architecture rather than simply reverting to the previous dataset"], correct: 1, explanation: "Clause 10.1 requires evaluating the root cause and ensuring non-recurrence. Simply reverting data fixes the immediate issue but fails to address why contaminated data entered the pipeline, whether other datasets are similarly affected, and whether clients who received incorrect outputs need notification. A completely new architecture (option C) may be disproportionate." },
      { question: "JurisBot has not conducted an AI impact assessment for the new generative AI legal memoranda feature. What finding should the recertification auditor raise?", options: ["Observation, since generative AI is a rapidly evolving technology and impact assessment methodologies for generative AI are still maturing, so the organization should develop one in the near future", "Nonconformity against Clause 8.4, as the organization is required to assess the impact of AI systems on individuals and society, and a generative AI system drafting legal documents carries significant risk of harm through incorrect legal advice", "Minor nonconformity, since the impact assessment requirement applies but the system is new and the organization can reasonably be expected to complete the assessment within the recertification cycle"], correct: 1, explanation: "Clause 8.4 requires AI system impact assessment. A generative AI system producing legal documents creates significant risks of harm. The absence of impact assessment for a system already in operation is not an observation (option A) or minor gap (option C) since the system is actively generating legal content that could cause real harm if incorrect." },
      { question: "During the recertification audit, the auditor examines the full three-year certification cycle. What distinguishes the recertification audit scope from a surveillance audit?", options: ["The recertification audit covers only the changes made since the last surveillance audit, focusing on areas that were not examined during the surveillance period", "The recertification audit evaluates the effectiveness of the management system in its entirety, its continued relevance and applicability to the scope, and the organization's demonstrated commitment to maintaining and improving the AIMS over the full certification cycle", "The recertification audit uses the same scope as surveillance audits but with more detailed sampling of each process area to provide higher assurance of conformity"], correct: 1, explanation: "Recertification evaluates the entire management system's effectiveness, relevance, and applicability, not just changes (option A) or deeper sampling of the same scope (option C). It considers the full certification cycle performance and whether the AIMS continues to be appropriate." },
      { question: "The incorrect contract clause incident resulted in litigation for JurisBot's client. What AIMS consideration does this raise regarding interested party communication?", options: ["No communication obligation exists since the error was in the client firm's contract, and JurisBot provided a tool rather than legal advice", "Clause 7.4 communication requirements and interested party management require the organization to determine how to communicate with affected parties about AI system failures, including incident notification to clients whose outputs may have been affected by the same data quality issue", "Communication is only required to the certification body and regulatory authorities, not to individual clients, since the AIMS focuses on system-level governance rather than individual incident management"], correct: 1, explanation: "Communication requirements extend to affected interested parties. If the same data quality issue could affect other client outputs, the organization has an obligation to assess the scope of impact and communicate appropriately. Limiting communication to regulators (option C) or claiming no obligation (option A) ignores the broader impact." },
      { question: "The recertification auditor notes that JurisBot's AI policy has not been reviewed since initial certification. What requirement is this assessed against?", options: ["No specific requirement mandates policy review frequency, so this is acceptable as long as the policy remains generally relevant to the organization's operations", "Clause 5.2 requires the AI policy to be appropriate to the organization's purpose, and management review under Clause 9.3 should consider whether the policy remains suitable, making two years without review a potential gap in leadership commitment", "The AI policy must be formally reviewed and reapproved annually by top management as a mandatory requirement of Clause 5.2"], correct: 1, explanation: "While no specific annual review frequency is mandated (option C is incorrect), the policy must remain appropriate to the organization's purpose. Over a two-year period with new AI systems and a significant incident, the policy should have been reviewed for continued suitability as part of management review processes. This indicates a potential gap in leadership commitment to AIMS maintenance." }
    ]},

    // SCENARIO 10: Insurance Underwriting AI (D1 Fundamentals + D2 Structure)
    { type: "scenario", scenario: "Atlas Reinsurance is exploring the use of reinforcement learning for dynamic pricing of catastrophe reinsurance policies. The system would learn from claims data, weather patterns, and economic indicators to adjust pricing in real time. The board's AI governance committee has asked the AIMS team to prepare a briefing on the AI technology fundamentals and governance considerations. The committee chair, who sits on the board, wants to understand the difference between the reinforcement learning approach and the supervised learning models currently used for mortality prediction. A board member asks whether ISO/IEC 38507 provides sufficient governance guidance or if ISO/IEC 42001 implementation is necessary. The chief actuary raises concerns about the reinforcement learning system's ability to explain its pricing decisions to regulators.", questions: [
      { question: "The committee chair asks about the difference between reinforcement learning for dynamic pricing and supervised learning for mortality prediction. What is the most relevant distinction for AIMS governance purposes?", options: ["Reinforcement learning systems learn through trial and error with reward signals and can develop unexpected strategies to maximize rewards, creating unique governance challenges around behavioral predictability and the need for constrained action spaces, compared to supervised learning which maps inputs to known outputs", "The primary difference is computational cost: reinforcement learning requires significantly more processing power, which affects infrastructure planning and resource allocation under Clause 7.1", "Supervised learning is more mature and well-understood, making it inherently lower risk for AIMS purposes, while reinforcement learning is experimental and should not be deployed in production until the technology matures"], correct: 0, explanation: "For AIMS governance, the critical distinction is behavioral: reinforcement learning agents can develop emergent strategies that weren't explicitly programmed, creating governance challenges around predictability, safety bounds, and the potential for unexpected market behavior. Computational cost (option B) is operational, not governance-critical. Maturity (option C) is an oversimplification since both can be appropriate depending on the application." },
      { question: "A board member asks whether ISO/IEC 38507 is sufficient for AI governance or if ISO/IEC 42001 is needed. What is the most accurate response?", options: ["ISO/IEC 38507 provides guidance for governing bodies on AI oversight but does not establish certifiable management system requirements; ISO/IEC 42001 provides the operational management system framework with requirements for risk assessment, controls, and continual improvement that ISO/IEC 38507 does not cover", "ISO/IEC 38507 is sufficient for board-level governance, and ISO/IEC 42001 is only necessary if the organization seeks external certification, which is optional", "ISO/IEC 42001 supersedes ISO/IEC 38507 and covers all governance aspects including board-level responsibilities, making ISO/IEC 38507 redundant for organizations implementing the full AIMS"], correct: 0, explanation: "ISO/IEC 38507 and ISO/IEC 42001 serve complementary purposes. ISO/IEC 38507 guides governing bodies on AI oversight principles, while ISO/IEC 42001 provides the certifiable operational framework. Neither supersedes the other (option C is wrong). ISO/IEC 38507 alone is insufficient for comprehensive AI management (option B underestimates the need for operational controls)." },
      { question: "The chief actuary is concerned about explainability of reinforcement learning pricing decisions to regulators. From an AIMS perspective, which approach best addresses this concern?", options: ["Implement post-hoc explainability tools that can approximate the reinforcement learning agent's decision rationale in terms understandable to regulators, and include this as a control in the AIMS with defined testing and validation procedures", "Replace the reinforcement learning approach with a more interpretable model architecture, since the AIMS requires that all AI systems be fully explainable to external stakeholders", "Document the reinforcement learning system's reward function and training environment parameters as the explanation mechanism, since regulators can understand the system's behavior through its design specifications"], correct: 0, explanation: "ISO/IEC 42001 does not require all AI to be fully explainable (option B is incorrect), but transparency and explainability controls must be appropriate to the context. For a regulated industry, post-hoc explainability tools with validation provide a practical approach. Simply documenting the reward function (option C) doesn't provide the decision-level explanations regulators typically require." },
      { question: "ISO/IEC TR 24028 addresses trustworthiness in AI. How does this technical report relate to Atlas Reinsurance's AIMS implementation for the reinforcement learning pricing system?", options: ["ISO/IEC TR 24028 provides mandatory requirements for AI trustworthiness that must be implemented alongside ISO/IEC 42001 controls for the pricing system to be compliant", "ISO/IEC TR 24028 provides informative guidance on trustworthiness considerations including transparency, robustness, and potential threats to AI systems, which can inform the risk assessment and control selection for the reinforcement learning system without imposing additional mandatory requirements", "ISO/IEC TR 24028 is applicable only to AI systems used in consumer-facing applications and does not apply to business-to-business reinsurance pricing systems"], correct: 1, explanation: "ISO/IEC TR 24028 is a technical report (TR), not a requirements standard, so it is informative rather than mandatory (option A is incorrect). It is not limited to consumer applications (option C is incorrect). It provides useful guidance on trustworthiness considerations that can inform the AIMS risk assessment and control design." },
      { question: "The Harmonized Structure shared by ISO/IEC 42001 with other management system standards uses a common clause numbering. Which clause specifically requires top management to ensure that the responsibilities and authorities for relevant roles are assigned, communicated, and understood within the organization?", options: ["Clause 5.1 Leadership and commitment, which establishes top management accountability for the overall effectiveness of the management system", "Clause 5.3, which requires top management to ensure that responsibilities and authorities for relevant roles are assigned, communicated, and understood within the organization", "Clause 7.2 Competence, which ensures that persons doing work under the organization's control are competent based on appropriate education, training, or experience"], correct: 1, explanation: "Clause 5.3 specifically addresses organizational roles, responsibilities, and authorities. Clause 5.1 (option A) covers broader leadership commitment. Clause 7.2 (option C) addresses competence, not role assignment. All three are related but serve distinct purposes within the Harmonized Structure." }
    ]},

    // STANDALONE QUESTIONS (30 questions)
    { type: "standalone", questions: [
      // D1 Fundamentals (7 remaining to reach 17 total)
      { question: "An organization uses a neural network that generates synthetic medical images for training other AI models. Under ISO/IEC 22989, which category of AI technique does this represent?", options: ["Supervised learning, since the generator is trained on labeled medical image datasets to produce outputs matching specific diagnostic categories", "Generative adversarial networks or similar generative models, which fall under the broader category of machine learning techniques that learn data distributions to create new data instances", "Transfer learning, since knowledge from the original medical images is being transferred into new synthetic representations"], correct: 1, explanation: "Generating synthetic data from learned distributions is a generative AI technique. While supervised learning (option A) may be part of the training process and transfer learning concepts (option C) may be involved, the fundamental technique of generating new data instances falls under generative modeling." },
      { question: "The NIST AI RMF identifies four core functions. An organization is mapping its AIMS processes to these functions and needs to understand which function addresses the systematic evaluation of AI risks. Which function is this?", options: ["Govern, which establishes the organizational structure and culture for responsible AI risk management throughout the AI lifecycle", "Measure, which employs quantitative and qualitative methods to analyze, assess, benchmark, and monitor AI risk and related impacts", "Map, which contextualizes risks by understanding the AI system's operating context, stakeholders, and potential impacts"], correct: 1, explanation: "The Measure function focuses on evaluating and monitoring AI risks using analytical methods. Govern (option A) establishes the governance framework. Map (option C) identifies and contextualizes risks. Measure is the function that systematically evaluates identified risks." },
      { question: "Under the EU AI Act, what obligation applies to providers of AI systems classified as 'limited risk'?", options: ["They must conduct a conformity assessment and register the AI system in the EU database before placing it on the market", "They must ensure transparency by informing users that they are interacting with an AI system, particularly for chatbots, emotion recognition, and deep fake generation", "They must implement a quality management system and maintain technical documentation throughout the AI system lifecycle"], correct: 1, explanation: "Limited risk AI systems face transparency obligations. Conformity assessment and registration (option A) apply to high-risk systems. Quality management systems (option C) are also high-risk requirements. Limited risk primarily requires disclosure to users about AI interaction." },
      { question: "ISO/IEC 23894 provides guidance on AI risk management. How does it relate to ISO 31000?", options: ["ISO/IEC 23894 replaces ISO 31000 for organizations using AI systems, providing AI-specific risk management processes that supersede the general risk management framework", "ISO/IEC 23894 builds upon ISO 31000 by applying general risk management principles to AI-specific contexts, addressing unique AI characteristics such as opacity, autonomy, and continuous learning", "ISO/IEC 23894 and ISO 31000 are independent standards that address different aspects of risk management and cannot be used together in an integrated risk management approach"], correct: 1, explanation: "ISO/IEC 23894 extends ISO 31000's general principles to AI-specific contexts. It does not replace ISO 31000 (option A) and is not independent from it (option C). It applies established risk management principles to the unique characteristics of AI systems." },
      { question: "A self-driving vehicle's AI system can perceive its environment and make navigation decisions but has no ability to form beliefs about other drivers' mental states or predict their intentions beyond observed behavior patterns. According to AI type classifications, what type of AI is this?", options: ["Limited memory AI, as it stores and uses recent environmental observations to inform current decisions but cannot reason about other agents' internal states", "Theory of mind AI, because it can predict other vehicles' movements based on observed behavior patterns and traffic rules", "Reactive AI, since it responds to current environmental inputs without using any stored past experiences"], correct: 0, explanation: "Limited memory AI uses stored observations to inform decisions, which describes the vehicle's use of recent environmental data. It is not theory of mind (option B) because predicting movement patterns is not the same as understanding mental states. It is not purely reactive (option C) because it does store and use recent observations." },
      { question: "An organization is evaluating whether its natural language processing chatbot that answers employee HR questions qualifies as an AI system. The system uses a rule-based decision tree with 500 predefined responses and no learning capability. Under ISO/IEC 22989, is this an AI system?", options: ["Yes, because it processes natural language inputs and generates contextual responses, which demonstrates AI capability regardless of the underlying technology", "Not necessarily; the classification depends on whether the system demonstrates capabilities typically associated with AI such as learning, reasoning, or adaptation, and a purely rule-based system without learning may not meet the AI system definition", "Yes, because ISO/IEC 22989 classifies all chatbot systems as AI systems regardless of their underlying architecture"], correct: 1, explanation: "ISO/IEC 22989's AI system definition requires capabilities typically associated with human intelligence. A purely rule-based system with predefined responses and no learning capability may not exhibit the adaptive or learning characteristics that define AI. The classification is not automatic based on the application type (options A and C incorrectly assume all chatbots are AI)." },
      { question: "According to ISO/IEC 22989, what is the relationship between 'data' and 'information' in the AI knowledge hierarchy?", options: ["Data and information are synonymous terms used interchangeably throughout the standard to describe inputs to AI systems", "Data is the raw representation of facts, while information is data that has been processed and organized in a way that gives it meaning and context within a specific domain", "Information is the raw input to AI systems, while data refers to the structured output produced after processing by machine learning algorithms"], correct: 1, explanation: "In the knowledge hierarchy, data is raw representation and information is processed, contextualized data. They are not synonymous (option A) and the relationship is not reversed (option C). This hierarchy continues upward to knowledge, which is retained and structured information." },

      // D2 AIMS Requirements (2 remaining to reach 5 total)
      { question: "An organization operating both ISO/IEC 27001 and ISO/IEC 42001 wants to conduct a single integrated internal audit covering both management systems. What must the audit program ensure?", options: ["The integrated audit must use separate audit teams for each standard, with a combined report issued at the conclusion to ensure that each standard's specific requirements receive dedicated expert attention", "The integrated audit must ensure that all requirements of both standards are covered, that auditors have competence in both information security and AI management, and that findings are traceable to the specific standard requirement they relate to", "Integrated audits are not permitted under the Harmonized Structure; each management system must be audited independently to maintain the integrity of each certification"], correct: 1, explanation: "Integrated audits are permitted and can be efficient. They require auditor competence across both domains and traceability of findings to specific requirements. Separate teams (option A) defeat the integration purpose. The Harmonized Structure actually facilitates integration (option C is incorrect)." },
      { question: "The Harmonized Structure requires that management system standards include 'documented information' rather than the older terms 'documents' and 'records.' What practical distinction does ISO/IEC 42001 maintain within documented information?", options: ["ISO/IEC 42001 treats all documented information identically with no distinction between types, applying the same retention and control requirements to all documentation", "ISO/IEC 42001 distinguishes between documented information that must be 'maintained' (documents that are kept current, such as policies and procedures) and documented information that must be 'retained' (records that provide evidence of activities performed and results achieved)", "ISO/IEC 42001 categorizes documented information into mandatory documents required by the standard and optional documents that organizations may choose to maintain based on their size and complexity"], correct: 1, explanation: "The distinction between 'maintain' (keep current) and 'retain' (keep as evidence) is a practical distinction within documented information. The standard does use these terms differently to indicate whether information should be actively updated or preserved as evidence. Not all documented information is treated identically (option A) and the categorization is not simply mandatory vs optional (option C)." },

      // D3 Planning (5 remaining to reach 20 total)
      { question: "During AIMS scope definition, a fintech organization decides to exclude its AI-powered anti-money laundering (AML) system because it was developed by a third-party vendor and operates as a managed service. Is this exclusion justified?", options: ["Yes, since the vendor manages the system, the AI-related risks are the vendor's responsibility and fall outside the organization's AIMS scope", "No, the AML system processes the organization's data and produces outputs that the organization relies on for regulatory compliance, creating interfaces and dependencies that Clause 4.3 requires the scope to address", "Yes, but only if the vendor holds their own ISO/IEC 42001 certification, which provides assurance that the system is governed under an appropriate AIMS"], correct: 1, explanation: "Clause 4.3 requires considering interfaces and dependencies. The AML system directly affects the organization's regulatory compliance and processes their data, creating dependencies that must be addressed in the AIMS scope. Using AI doesn't transfer governance responsibility (option A), and vendor certification (option C) doesn't eliminate the organization's own governance obligations." },
      { question: "An organization's AI risk assessment identifies a risk that an AI hiring tool may discriminate based on gender. The risk score is moderate. The AI ethics committee recommends treating this risk with maximum urgency regardless of the score. How should the AIMS handle this?", options: ["Follow the risk score strictly, as the risk assessment methodology was approved and deviating from it undermines the objectivity of the risk management framework", "Consider both the quantitative risk score and qualitative factors including regulatory requirements, ethical obligations, and stakeholder expectations, as risk treatment decisions should account for context beyond numerical scores", "Override the risk score and treat the risk as critical, since any discrimination risk in hiring must be treated with maximum priority regardless of the risk assessment methodology"], correct: 1, explanation: "Risk treatment decisions should consider multiple factors. Strict numerical adherence (option A) ignores important contextual factors. Automatic override (option C) undermines the risk assessment framework. The appropriate approach considers both the quantitative score and qualitative factors such as regulatory obligations and ethical considerations." },
      { question: "Clause 6.3 requires planning changes to the AIMS when the organization determines the need for changes. An organization is migrating its AI infrastructure from on-premises to cloud. What must the change planning address?", options: ["Only the technical aspects of the migration including data transfer, system configuration, and performance testing in the new cloud environment", "The purpose of the change, potential consequences for AIMS integrity, availability of resources, and allocation or reallocation of responsibilities and authorities", "A formal change request submitted to the certification body for approval before the migration proceeds, since infrastructure changes may affect the certification scope"], correct: 1, explanation: "Clause 6.3 requires considering purpose, consequences, AIMS integrity, resources, and responsibilities. Technical aspects (option A) are important but don't satisfy the AIMS change planning requirement. Certification body notification (option C) may be appropriate for scope changes but is not the primary AIMS requirement for change planning." },
      { question: "An organization establishing its AI policy wants to include a commitment to 'ethical AI development.' The lead implementer advises against this specific wording. Why?", options: ["ISO/IEC 42001 does not address ethics, so including ethical commitments in the AI policy would extend the AIMS beyond the standard's scope and create unnecessary audit obligations", "While ethical commitment is appropriate, the policy should use concrete, assessable commitments such as fairness, transparency, and accountability rather than the broadly interpreted term 'ethical,' which may not provide a clear framework for setting measurable AI objectives", "The term 'ethical' is subjective and varies across cultures, so it should be avoided in an internationally certified management system to prevent disagreements during certification audits"], correct: 1, explanation: "The AI policy must provide a framework for setting objectives (Clause 5.2). 'Ethical AI' is too vague to drive measurable objectives. Concrete terms like fairness, transparency, and accountability are more actionable. ISO/IEC 42001 does address responsible AI principles (option A is incorrect), and cultural variation (option C) is not the primary reason to avoid vague commitments." },
      { question: "An organization identifies that its AI chatbot's training data contains personally identifiable information that was collected without explicit consent for AI training purposes. During risk assessment, this is flagged as a legal compliance risk. What should the risk treatment plan prioritize?", options: ["Anonymizing the training data retroactively and continuing to use the model, since removing PII from the dataset eliminates the compliance risk without disrupting AI system operations", "Assessing the legal basis for data processing, determining whether the current model must be retrained with compliant data, evaluating notification obligations to affected individuals, and establishing data governance controls to prevent recurrence", "Destroying the training data and the trained model immediately, since using data collected without consent contaminates the entire model and cannot be remediated through anonymization"], correct: 1, explanation: "The risk treatment must comprehensively address legal compliance. Simple anonymization (option A) may not be legally sufficient since the model has already learned from non-consented data. Immediate destruction (option C) may be disproportionate and should be determined through proper legal assessment. The correct approach evaluates the full legal situation and implements appropriate remediation." },

      // D4 Implementation (3 remaining to reach 18 total)
      { question: "An organization's AIMS communication plan (Clause 7.4) specifies internal communications only. External stakeholders including customers, regulators, and the public are not addressed. Is this plan sufficient?", options: ["Yes, AIMS communications are primarily internal since the management system governs internal processes and external communication is handled by corporate communications functions", "No, Clause 7.4 requires determining both internal and external communications relevant to the AIMS, including what, when, with whom, and how to communicate about AI governance matters", "Yes, external communication requirements are addressed separately under interested party management (Clause 4.2) and do not need to be duplicated in the communication plan"], correct: 1, explanation: "Clause 7.4 explicitly requires determining internal and external communications. Limiting to internal only leaves a gap in how the organization communicates with regulators, customers, and other external parties about AI governance. While Clause 4.2 identifies interested parties (option C), the communication plan must address how to communicate with them." },
      { question: "During AIMS implementation, the project team discovers that the organization's AI model validation process tests models only against accuracy metrics. What additional validation considerations does an AIMS require?", options: ["Accuracy is the primary validation metric and additional testing is only required if the AI system is classified as high-risk under the EU AI Act", "Validation should also assess fairness across relevant demographic groups, robustness to adversarial inputs, performance on edge cases, and alignment with the organization's AI policy commitments and applicable Annex A controls", "Validation should include user acceptance testing and business stakeholder sign-off, which are the primary gaps when only technical accuracy is measured"], correct: 1, explanation: "AIMS-aligned validation must go beyond accuracy to include AI-specific considerations such as fairness, robustness, and policy alignment. EU AI Act classification (option A) is not the trigger for comprehensive validation under ISO/IEC 42001. User acceptance testing (option C) is important but doesn't address the AI-specific validation gaps." },
      { question: "An organization deploys an AI system that generates content visible to the public. Under Annex A controls related to transparency, what is the minimum expected control?", options: ["The organization must publish the full technical specification of the AI model including architecture, training data sources, and hyperparameters to enable public scrutiny", "The organization should implement controls ensuring that AI-generated content is identifiable as such and that individuals interacting with the AI system are informed, with the level of disclosure proportionate to the risk and context", "The organization must obtain informed consent from every individual who might view the AI-generated content before it is published or displayed"], correct: 1, explanation: "Transparency controls should ensure AI-generated content is identifiable and users are informed. Full technical disclosure (option A) may expose proprietary information and is not typically required. Individual consent for public content (option C) is impractical. The appropriate level of transparency is proportionate to risk and context." },

      // D5 Monitoring (3 remaining to reach 10 total)
      { question: "An organization monitors its AI systems using automated dashboards that track 25 metrics in real time. However, no one has reviewed the dashboard data for the past three months. Does the monitoring program satisfy Clause 9.1?", options: ["Yes, automated monitoring satisfies the requirement since the data is being collected continuously and would reveal issues if someone examined it", "No, Clause 9.1 requires not only monitoring but also determining when results shall be analyzed and evaluated, and unreviewed data cannot contribute to AIMS performance evaluation or drive improvement", "Yes, as long as the dashboards include automated alerts for threshold breaches, since real-time alerting substitutes for human review of monitoring data"], correct: 1, explanation: "Monitoring without analysis is incomplete. Clause 9.1 requires determining when to analyze and evaluate results, not just when to collect data. Automated collection (option A) and alerts (option C) are useful but do not satisfy the requirement for analysis and evaluation that informs management decisions." },
      { question: "During an internal audit, the auditor finds that the organization's AI system performance baselines were established using test data that does not represent the production environment. What should the auditor conclude?", options: ["The monitoring baselines may be invalid, meaning the organization cannot reliably determine whether AI system performance has degraded or improved in production, undermining the validity of monitoring results required by Clause 9.1", "This is an acceptable practice since baselines are typically established during development and testing, and production performance naturally varies from test conditions", "The baselines should be noted as a limitation in the monitoring reports but do not constitute a nonconformity since the organization is monitoring against defined criteria"], correct: 0, explanation: "Clause 9.1 requires methods for monitoring that ensure valid results. If baselines don't represent production conditions, the monitoring results cannot reliably indicate whether the system is performing acceptably. This is not merely a documented limitation (option C) since it fundamentally undermines monitoring validity. Production variation from test conditions (option B) is exactly why baselines should be production-representative." },
      { question: "An organization's management review agenda covers all required ISO/IEC 42001 Clause 9.3 inputs, but the review is conducted by the AIMS manager alone without top management participation. Does this satisfy the requirement?", options: ["Yes, the AIMS manager can conduct the review on behalf of top management as long as the results are communicated upward and documented appropriately", "No, management review is a Clause 9.3 requirement that involves top management evaluating the AIMS and making decisions about improvement and resource needs, and delegation to the AIMS manager alone does not satisfy this requirement", "Yes, if the AIMS manager has been delegated authority for management review by top management through a documented authorization"], correct: 1, explanation: "Management review is a top management responsibility under Clause 9.3, linked to leadership requirements in Clause 5.1. The review requires management decisions on improvement and resources that cannot be fully delegated. While the AIMS manager can prepare inputs, top management must participate in the evaluation and decision-making." },

      // D6 Improvement & Audit (4 remaining to reach 10 total)
      { question: "A certification body schedules a Stage 1 audit and Stage 2 audit on consecutive days. Is this scheduling appropriate?", options: ["Yes, conducting both stages consecutively is efficient and minimizes disruption to the organization's operations", "No, there must be a reasonable interval between Stage 1 and Stage 2 to allow the organization to address any Stage 1 findings and to allow the audit team to plan Stage 2 based on Stage 1 results", "Yes, but only for small organizations where the AIMS scope is limited and both stages can be completed within normal working hours"], correct: 1, explanation: "Stage 1 is meant to evaluate readiness for Stage 2. If both stages occur consecutively, the organization has no opportunity to address Stage 1 findings, and the audit team cannot use Stage 1 results to properly plan Stage 2. A reasonable interval is necessary regardless of organization size (option C)." },
      { question: "During a Stage 2 certification audit, the auditor discovers that the organization's AI risk assessment was completed by an external consultant who is no longer available, and no internal staff can explain the risk assessment methodology or results. What finding should be raised?", options: ["Observation, noting that the organization should develop internal risk assessment capability to ensure business continuity", "Nonconformity, as the organization must demonstrate competence in its own AIMS processes, and inability to explain the risk assessment suggests lack of internal understanding and ownership of a critical AIMS process", "No finding, since using external consultants for risk assessment is acceptable and the quality of the assessment should be evaluated on its documented content rather than staff knowledge"], correct: 1, explanation: "While using external consultants is acceptable, the organization must understand and own its AIMS processes. If no one can explain the risk assessment methodology or results, the organization lacks the competence required by Clause 7.2 and cannot effectively maintain or update the risk assessment. The documented content (option C) is necessary but not sufficient without organizational understanding." },
      { question: "An organization receives a major nonconformity during a surveillance audit. They submit evidence of corrective action within the agreed timeframe, but the certification body determines the evidence is insufficient. What happens next?", options: ["The certification body must accept the evidence and grant additional time, as the organization met the agreed deadline", "The certification body may conduct a follow-up audit to verify corrections, extend the deadline with additional requirements, or proceed with suspension depending on the severity and the organization's response", "The certification is automatically suspended since the original corrective action was insufficient, and reinstatement requires a full recertification audit"], correct: 1, explanation: "The certification body has options when evidence is insufficient. Automatic acceptance (option A) would undermine the corrective action process. Automatic suspension and full recertification (option C) may be disproportionate. The certification body evaluates the situation and selects the appropriate response, which may include follow-up verification or suspension." },
      { question: "Under ISO/IEC 17021-1, what is the certification body's obligation regarding the use of publicly available information about the certified client?", options: ["The certification body must not consider public information and should base its assessment solely on evidence gathered during formal audit activities", "The certification body should monitor publicly available information about certified clients as relevant, and significant issues may trigger unscheduled audits or other actions to verify continued compliance", "The certification body may review public information only during scheduled surveillance and recertification audits, not between audit cycles"], correct: 1, explanation: "ISO/IEC 17021-1 requires certification bodies to be aware of relevant public information about certified clients. Ignoring public information (option A) would be negligent. Limiting review to audit cycles only (option C) misses the ongoing responsibility. Significant public issues can trigger additional certification body actions between scheduled audits." },

      // Additional D3 Planning questions
      { question: "An organization defines its AIMS scope to include only AI systems that process personal data, excluding AI systems used for internal operational optimization that do not process personal data. Is this scoping approach appropriate?", options: ["Yes, since AI systems that do not process personal data pose minimal risk to individuals and can be legitimately excluded from the AIMS scope", "Not necessarily; Clause 4.3 requires considering all factors including internal and external issues and interested party requirements, and operational AI systems may create risks beyond personal data processing such as safety risks, environmental impacts, or business continuity threats that warrant inclusion", "Yes, aligning the AIMS scope with data protection scope ensures consistency with GDPR and simplifies compliance management across governance frameworks"], correct: 1, explanation: "AIMS scope should be based on comprehensive analysis under Clause 4.3, not limited to personal data considerations alone. AI systems can create risks unrelated to personal data including safety, environmental, and business continuity risks. Aligning with GDPR scope (option C) may simplify compliance but misses AI-specific risks that the AIMS should address." },
      { question: "During risk assessment, the AI team identifies that a model could produce harmful outputs if exposed to adversarial inputs specifically crafted to exploit model vulnerabilities. How should this risk be categorized in the AIMS?", options: ["As an information security risk to be managed under the existing ISMS rather than the AIMS, since adversarial inputs are a form of cybersecurity attack", "As an AI-specific risk under Clause 6.1.4, since adversarial robustness is an inherent characteristic of AI systems that affects their reliability and safety, requiring AI-specific risk treatment including model hardening, input validation, and anomaly detection", "As an external threat that should be documented in the context analysis under Clause 4.1 but does not require specific risk treatment since the likelihood of targeted adversarial attacks is low for most organizations"], correct: 1, explanation: "Adversarial vulnerability is an AI-specific risk distinct from general cybersecurity. While information security controls (option A) are relevant, the risk requires AI-specific treatment such as model hardening. Dismissing the likelihood (option C) ignores a well-documented AI vulnerability category that the AIMS should address." },

      // Additional D4 Implementation question
      { question: "An organization discovers that two different AI systems in its portfolio use inconsistent definitions of the same data fields, leading to conflicting outputs when the systems are used together. What AIMS control area should address this?", options: ["Data governance controls, which should ensure consistent data definitions, quality standards, and interoperability across AI systems within the AIMS scope, preventing semantic inconsistencies that affect output reliability", "Operational planning and control under Clause 8.1, which should include integration testing procedures for AI systems that share data or produce related outputs", "Documented information requirements under Clause 7.5, which should include a data dictionary that standardizes field definitions across all AI systems"], correct: 0, explanation: "Data governance controls address the systematic management of data quality, consistency, and interoperability across AI systems. While operational testing (option B) and documentation (option C) are relevant supporting measures, the primary control area is data governance, which establishes the standards and processes that prevent such inconsistencies from arising." },

      // Additional D5 Monitoring question
      { question: "An organization has implemented AI monitoring that tracks model accuracy and drift metrics, but does not monitor for changes in the external regulatory environment that affect its AI systems. What gap does this represent?", options: ["No gap, since regulatory monitoring is a legal function separate from the AIMS monitoring program, which should focus on technical AI performance metrics", "A gap in the monitoring program's scope, since Clause 9.1 combined with Clause 4.1 context monitoring requires the organization to monitor changes in external issues including regulatory developments that affect the AIMS", "A minor gap that can be addressed by subscribing to regulatory newsletters, which satisfies the external monitoring requirement without formalizing it within the AIMS monitoring program"], correct: 1, explanation: "Monitoring under the AIMS must extend beyond technical metrics to include changes in the external context (Clause 4.1) that affect the AIMS. Regulatory changes directly impact AI governance requirements. Separating regulatory monitoring (option A) creates blind spots. Informal newsletter subscriptions (option C) lack the rigor of a structured monitoring process within the AIMS." },

      // Additional D6 Audit questions
      { question: "An audit team conducting an ISO/IEC 42001 certification audit includes a technical expert in deep learning but the lead auditor has limited understanding of AI technology. During the audit, the technical expert identifies a significant concern about model validation practices. Who has the authority to raise this as a formal audit finding?", options: ["The technical expert can raise the finding independently since they identified the concern and have the technical expertise to assess its significance", "Only the lead auditor or an auditor on the team can raise formal audit findings; the technical expert provides input and expertise to the audit team but does not independently raise findings or make audit judgments", "Either the technical expert or the lead auditor can raise the finding, as ISO/IEC 17021-1 grants equal authority to all audit team members regardless of their role designation"], correct: 1, explanation: "Under ISO/IEC 17021-1, technical experts provide knowledge and expertise to the audit team but do not act as auditors. They cannot independently raise findings or make audit judgments. The lead auditor or auditors must evaluate the technical expert's input and determine whether to raise it as a formal finding. The roles have distinct authorities (option C is incorrect)." },
      { question: "An organization's AIMS has been certified for 30 months. The certification body informs them that the recertification audit must be completed before the current certificate expires. The organization requests a 3-month extension. What does ISO/IEC 17021-1 allow?", options: ["The certification body can grant extensions at its discretion as long as the organization demonstrates continued AIMS operation through documented evidence", "If the recertification audit cannot be completed before certificate expiry, the certification body may reduce the subsequent certification cycle to maintain the original expiry date rhythm, but cannot simply extend the current certificate", "The certification body must allow a 90-day grace period for recertification audits as specified in ISO/IEC 17021-1, during which the current certificate remains valid"], correct: 1, explanation: "ISO/IEC 17021-1 does not provide for arbitrary extensions (option A) or standardized grace periods (option C). If recertification cannot be completed before expiry, the certification body may adjust the subsequent cycle. The emphasis is on completing recertification before expiry, and failure to do so may result in certification lapse requiring a new initial audit." }
    ]}
  ]
};
